import{f as e,o as t,c as r,a7 as s}from"./chunks/framework.DDLK82Pw.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"S6-Go/阶段17-分布式存储与计算.md","filePath":"S6-Go/阶段17-分布式存储与计算.md","lastUpdated":1780493670000}'),a={name:"S6-Go/阶段17-分布式存储与计算.md"};function n(l,o,i,d,c,g){return t(),r("div",null,[...o[0]||(o[0]=[s('<h2 id="💾-阶段十七-分布式存储与计算" tabindex="-1">💾 阶段十七：分布式存储与计算 <a class="header-anchor" href="#💾-阶段十七-分布式存储与计算" aria-label="Permalink to &quot;💾 阶段十七：分布式存储与计算&quot;">​</a></h2><h3 id="_17-1-分布式协调" tabindex="-1">17.1 分布式协调 <a class="header-anchor" href="#_17-1-分布式协调" aria-label="Permalink to &quot;17.1 分布式协调&quot;">​</a></h3><h4 id="q65-etcd-在-go-微服务中扮演什么角色-如何保证高可用" tabindex="-1">Q65: etcd 在 Go 微服务中扮演什么角色？如何保证高可用？ <a class="header-anchor" href="#q65-etcd-在-go-微服务中扮演什么角色-如何保证高可用" aria-label="Permalink to &quot;Q65: etcd 在 Go 微服务中扮演什么角色？如何保证高可用？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：🔥 高频</p><p><strong>考点</strong>：Raft 协议、服务发现、配置中心、Watch 机制。</p><p><strong>💡 记忆关键词</strong>：Raft 协议、服务注册、配置推送、奇数节点</p><p><strong>答案要点</strong>：</p><ul><li><strong>角色</strong>：服务注册发现、分布式锁、Leader 选举、配置动态推送。</li><li><strong>高可用</strong>：奇数节点部署（3/5/7），Raft 协议保证多数派写入；定期 Snapshot 压缩日志；监控 <code>etcd_server_has_leader</code> 指标。</li><li><strong>Go 客户端</strong>：使用 <code>go.etcd.io/etcd/client/v3</code>，注意连接复用、超时设置、Watch 重连逻辑。</li></ul><h4 id="q66-redis-cluster-与-codis-的区别-go-中如何选择客户端" tabindex="-1">Q66: Redis Cluster 与 Codis 的区别？Go 中如何选择客户端？ <a class="header-anchor" href="#q66-redis-cluster-与-codis-的区别-go-中如何选择客户端" aria-label="Permalink to &quot;Q66: Redis Cluster 与 Codis 的区别？Go 中如何选择客户端？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：分片策略、客户端路由、运维成本、一致性哈希。</p><p><strong>💡 记忆关键词</strong>：去中心化、代理模式、MOVED 重定向、Hash Tag</p><p><strong>答案要点</strong>：</p><ul><li><strong>Redis Cluster</strong>：官方方案，去中心化，客户端需支持 <code>MOVED</code>/<code>ASK</code> 重定向；适合中小规模。</li><li><strong>Codis</strong>：代理模式，对客户端透明，支持平滑扩容；适合大规模、运维团队强的场景。</li><li><strong>Go 客户端</strong>：<code>redis/go-redis/v9</code>（支持 Cluster）、<code>HSET</code>（哈希槽路由）；避免跨槽批量操作（使用 <code>Hash Tag</code>）。</li></ul><h3 id="_17-2-大数据与-olap" tabindex="-1">17.2 大数据与 OLAP <a class="header-anchor" href="#_17-2-大数据与-olap" aria-label="Permalink to &quot;17.2 大数据与 OLAP&quot;">​</a></h3><h4 id="q67-go-如何高效对接-clickhouse-进行实时数据分析" tabindex="-1">Q67: Go 如何高效对接 ClickHouse 进行实时数据分析？ <a class="header-anchor" href="#q67-go-如何高效对接-clickhouse-进行实时数据分析" aria-label="Permalink to &quot;Q67: Go 如何高效对接 ClickHouse 进行实时数据分析？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：列式存储、批量插入、连接池、物化视图。</p><p><strong>💡 记忆关键词</strong>：列式存储、批量插入、异步写入、物化视图</p><p><strong>答案要点</strong>：</p><ul><li><strong>驱动</strong>：使用 <code>ClickHouse/clickhouse-go/v2</code>（官方推荐，支持原生协议）。</li><li><strong>优化</strong>： <ol><li>批量插入（<code>Batch</code> 模式，每批 1w~10w 行）。</li><li>使用 <code>AsyncInsert</code> 异步写入，降低延迟。</li><li>避免单行查询，利用物化视图预聚合。</li><li>连接池配置 <code>MaxOpenConns</code>、<code>ConnMaxLifetime</code> 匹配 CH 服务端限制。</li></ol></li></ul><hr>',22)])])}const _=e(a,[["render",n]]);export{p as __pageData,_ as default};
